CREATE TABLE Users (user_id INT PRIMARY KEY, name VARCHAR(255) NOT NULL, email VARCHAR(255) UNIQUE NOT NULL, password VARCHAR(255) NOT NULL CHECK (LEN(password) >= 8), city VARCHAR(255) CHECK (city IN ('Warangal', 'Hanamkonda', 'Kazipet')));
CREATE TABLE Products (product_id INT PRIMARY KEY, name VARCHAR(255) NOT NULL, category VARCHAR(255) CHECK (category IN ('Electronics', 'Clothing', 'Groceries')), price DECIMAL(10, 2) CHECK (price > 0), stock INT CHECK (stock >= 0));
CREATE TABLE Orders (order_id INT PRIMARY KEY, user_id INT FOREIGN KEY REFERENCES Users(user_id), product_id INT FOREIGN KEY REFERENCES Products(product_id), quantity INT CHECK (quantity > 0), order_date DATE, CHECK (quantity * (SELECT price FROM Products WHERE product_id = Orders.product_id) <= 100000), UNIQUE (user_id, product_id));